package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class)class AppointmentAvailabilityServiceImplTest {@Mock DoctorScheduleDao schedules;@Mock AppointmentDao appointments;@Mock DoctorDao doctors;AppointmentAvailabilityServiceImpl service;@BeforeEach void init(){service=new AppointmentAvailabilityServiceImpl(schedules,appointments,doctors);}@Test void combinesWindowsExcludesBookedAndDeduplicates()throws Exception{LocalDate day=LocalDate.now().plusDays(2);Doctor d=new Doctor();d.setDoctorId(1L);d.setStatus("ACTIVE");d.setUserStatus("ACTIVE");when(doctors.findById(1L)).thenReturn(Optional.of(d));DoctorSchedule a=window(1L,LocalTime.of(9,0),LocalTime.of(10,0),30),b=window(2L,LocalTime.of(9,30),LocalTime.of(10,30),30);when(schedules.findAvailableByDoctorAndDay(1L,day.getDayOfWeek().name())).thenReturn(List.of(a,b));when(appointments.findBookedStartTimes(1L,day)).thenReturn(List.of(LocalTime.of(9,30)));List<AvailableSlot>x=service.getAvailableSlots(1L,day,null);assertEquals(List.of(LocalTime.of(9,0),LocalTime.of(10,0)),x.stream().map(AvailableSlot::getStartTime).toList());}@Test void inactiveDoctorAndNoScheduleAreEmpty()throws Exception{Doctor d=new Doctor();d.setStatus("INACTIVE");d.setUserStatus("ACTIVE");when(doctors.findById(1L)).thenReturn(Optional.of(d));assertTrue(service.getAvailableSlots(1L,LocalDate.now().plusDays(1),null).isEmpty());}@Test void currentAppointmentSlotCanBeExcluded()throws Exception{LocalDate day=LocalDate.now().plusDays(1);Doctor d=new Doctor();d.setDoctorId(1L);d.setStatus("ACTIVE");d.setUserStatus("ACTIVE");when(doctors.findById(1L)).thenReturn(Optional.of(d));when(schedules.findAvailableByDoctorAndDay(eq(1L),anyString())).thenReturn(List.of(window(1L,LocalTime.of(9,0),LocalTime.of(9,30),30)));when(appointments.findBookedStartTimes(1L,day)).thenReturn(List.of(LocalTime.of(9,0)));Appointment a=new Appointment();a.setAppointmentId(7L);a.setDoctorId(1L);a.setAppointmentDate(day);a.setStartTime(LocalTime.of(9,0));when(appointments.findById(7L)).thenReturn(Optional.of(a));assertEquals(1,service.getAvailableSlots(1L,day,7L).size());}private DoctorSchedule window(Long id,LocalTime a,LocalTime b,int duration){DoctorSchedule s=new DoctorSchedule();s.setScheduleId(id);s.setStartTime(a);s.setEndTime(b);s.setSlotDurationMinutes(duration);s.setAvailable(true);return s;}}
